# ============================================================
# program.ps1  (G071_NUCELO_CommBench ST-Link SWD flash)
# ------------------------------------------------------------
# Generated by stm32-stlink-flash skill (customised for a
# two-ST-Link bench: G071 NUCLEO + a second H7 board).
#
# 重點客製: 用 Board Name (預設 NUCLEO-G071) 鎖定目標 probe，
#           並把 sn=<選中序號> 帶進每一個 CLI 呼叫，
#           確保永遠只燒 G071、不會誤燒同時接著的 H7。
#           一律 program + verify (不提供跳過 verify 的旁支)。
#
# Stages:
#   [1/4] Scan hex/  -> pick newest .hex (single model, no menu)
#   [2/4] Detect ST-Link -> 依 TARGET_BOARD / TARGET_SN 選定目標 probe
#   [3/4] STM32_Programmer_CLI -c port=SWD sn=<SN> -w <hex> -v
#   [4/4] hardware reset -> APP 開始執行
# Edit config.ini for tunables (HEX dir, SWD freq, target board, etc).
# ============================================================

[CmdletBinding()]
param(
    [string]$ConfigPath = "",
    [string]$LogPath    = $null,
    [switch]$Pause
)

$ErrorActionPreference = "Stop"

# Resolve script directory : 防 PowerShell 5.1 在 param() default 內取 $PSScriptRoot
# 偶爾拿到空字串的邊界 bug (cmd -> powershell -File 鏈 + -NoProfile)。
$scriptDir = $PSScriptRoot
if (-not $scriptDir)
{
    if ($MyInvocation.MyCommand.Path)
    {
        $scriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
    }
    else
    {
        $scriptDir = (Get-Location).Path
    }
}
if ([string]::IsNullOrEmpty($ConfigPath))
{
    $ConfigPath = Join-Path $scriptDir "config.ini"
}

try {
    [Console]::OutputEncoding = [System.Text.Encoding]::UTF8
    [Console]::InputEncoding  = [System.Text.Encoding]::UTF8
    $OutputEncoding = [System.Text.Encoding]::UTF8
} catch {}

function Wait-OnExit
{
    param([int]$Code)
    if ($Pause)
    {
        Write-Host ""
        Write-Host ("---- exit code = {0} ----  press any key to close ..." -f $Code) -ForegroundColor Cyan
        try { [void]$Host.UI.RawUI.ReadKey('NoEcho,IncludeKeyDown') } catch { [void](Read-Host) }
    }
    exit $Code
}

trap
{
    Write-Host ""
    Write-Host "[FATAL] Uncaught exception:" -ForegroundColor Red
    Write-Host $_.Exception.Message -ForegroundColor Red
    if ($_.ScriptStackTrace) { Write-Host $_.ScriptStackTrace -ForegroundColor DarkRed }
    Wait-OnExit 99
}

if ($LogPath)
{
    try { Start-Transcript -Path $LogPath -Append -IncludeInvocationHeader | Out-Null } catch {}
}

# ============================================================
# INI reader
# ============================================================
function Read-Ini
{
    param([string]$Path)
    $ini = @{}
    $section = "_"
    $ini[$section] = @{}
    foreach ($line in Get-Content -LiteralPath $Path -Encoding UTF8)
    {
        $t = $line.Trim()
        if ($t -eq "" -or $t.StartsWith(";") -or $t.StartsWith("#")) { continue }
        if ($t -match "^\[(.+)\]$")
        {
            $section = $matches[1]
            if (-not $ini.ContainsKey($section)) { $ini[$section] = @{} }
            continue
        }
        if ($t -match "^([^=]+?)\s*=\s*(.*)$")
        {
            $ini[$section][$matches[1].Trim()] = $matches[2].Trim()
        }
    }
    return $ini
}

function Find-StmProgrammerCli
{
    param([string]$Preferred)
    $script:_cliTried = @()
    if ($Preferred -and $Preferred -ne "AUTO")
    {
        $script:_cliTried += $Preferred
        if (Test-Path -LiteralPath $Preferred) { return $Preferred }
    }
    $fromPath = Get-Command STM32_Programmer_CLI.exe -ErrorAction SilentlyContinue
    if ($fromPath) { return $fromPath.Source }
    $drives = @(Get-PSDrive -PSProvider FileSystem -ErrorAction SilentlyContinue |
                Where-Object { $_.Root -match '^[A-Z]:\\$' })
    $subPaths = @(
        'Program Files\STMicroelectronics\STM32Cube\STM32CubeProgrammer\bin\STM32_Programmer_CLI.exe',
        'Program Files (x86)\STMicroelectronics\STM32Cube\STM32CubeProgrammer\bin\STM32_Programmer_CLI.exe',
        'STMicroelectronics\STM32Cube\STM32CubeProgrammer\bin\STM32_Programmer_CLI.exe',
        'ST\STM32CubeProgrammer\bin\STM32_Programmer_CLI.exe',
        'STM32CubeProgrammer\bin\STM32_Programmer_CLI.exe'
    )
    foreach ($drv in $drives)
    {
        foreach ($s in $subPaths)
        {
            $c = Join-Path $drv.Root $s
            $script:_cliTried += $c
            if (Test-Path -LiteralPath $c) { return $c }
        }
    }
    # Recursive fallback : 涵蓋 STM32CubeIDE 內建 plugin 版 (路徑含動態版本號無法 hardcode)
    foreach ($drv in $drives)
    {
        foreach ($s in @('STMicroelectronics','Program Files\STMicroelectronics','Program Files (x86)\STMicroelectronics','ST'))
        {
            $root = Join-Path $drv.Root $s
            if (Test-Path -LiteralPath $root)
            {
                $hit = Get-ChildItem -LiteralPath $root -Filter 'STM32_Programmer_CLI.exe' -Recurse -Depth 6 -ErrorAction SilentlyContinue | Select-Object -First 1
                if ($hit) { return $hit.FullName }
            }
        }
    }
    return $null
}

function Resolve-RelativePath
{
    param([string]$Base, [string]$Path)
    if ([System.IO.Path]::IsPathRooted($Path)) { return $Path }
    return [System.IO.Path]::GetFullPath((Join-Path $Base $Path))
}

# ============================================================
# Load config
# ============================================================
if (-not (Test-Path $ConfigPath))
{
    Write-Host "[ERR] config.ini not found: $ConfigPath" -ForegroundColor Red
    Wait-OnExit 12
}
$cfg = Read-Ini $ConfigPath

$hexDirRaw   = $cfg.firmware.HEX_DIR
$cliPath     = Find-StmProgrammerCli -Preferred $cfg.programmer.CLI_PATH
$swdFreq     = [int]($cfg.programmer.SWD_FREQ_KHZ)
$resetMode   = $cfg.programmer.RESET_MODE
$targetBoard = if ($cfg.target.TARGET_BOARD) { $cfg.target.TARGET_BOARD.Trim() } else { "" }
$targetSnCfg = if ($cfg.target.TARGET_SN)    { $cfg.target.TARGET_SN.Trim() }    else { "" }

Write-Host "============================================================" -ForegroundColor Cyan
Write-Host " G071_NUCELO_CommBench  ST-Link (SWD) Flash" -ForegroundColor Cyan
Write-Host "============================================================" -ForegroundColor Cyan
Write-Host (" CLI freq      : {0} kHz / reset {1}" -f $swdFreq, $resetMode)
Write-Host (" Target board  : {0}" -f $(if ($targetSnCfg) { "SN=$targetSnCfg" } elseif ($targetBoard) { "$targetBoard (by board name)" } else { "(any single probe)" }))
Write-Host (" Mode          : Program + Verify")
Write-Host ""

# ============================================================
# Step 1 — pick HEX (single model : newest under hex/)
# ============================================================
Write-Host "[1/4] Selecting HEX file ..." -ForegroundColor Yellow
$hexDir = Resolve-RelativePath -Base $scriptDir -Path $hexDirRaw
if (-not (Test-Path -LiteralPath $hexDir))
{
    Write-Host "[ERR] HEX dir does not exist: $hexDir" -ForegroundColor Red
    Wait-OnExit 11
}
$allHex = @(Get-ChildItem -LiteralPath $hexDir -Filter "*.hex" -ErrorAction SilentlyContinue)
if ($allHex.Count -eq 0)
{
    Write-Host "[ERR] No .hex under $hexDir" -ForegroundColor Red
    Write-Host "      把要燒的 .hex 放進 hex\ 資料夾 (檔名含 8 碼日期會自動挑最新)" -ForegroundColor DarkGray
    Wait-OnExit 11
}
# Sort: YYMMDDVV / YYYYMMDD 8-digit date code DESC + LastWriteTime DESC tiebreaker
$sortExpr = @{
    Expression = { if ($_.Name -match '(\d{8})') { [int64]$matches[1] } else { 0 } }
    Descending = $true
}, @{
    Expression = 'LastWriteTime'
    Descending = $true
}
$h = @($allHex | Sort-Object $sortExpr)[0]
$hexFile = $h.FullName
$hexSize = (Get-Item -LiteralPath $hexFile).Length
Write-Host "[OK ] auto-selected: $($h.Name) ($hexSize bytes)" -ForegroundColor Green
if ($allHex.Count -gt 1)
{
    Write-Host "      (hex\ 內有 $($allHex.Count) 個檔，挑了日期碼最新那個)" -ForegroundColor DarkGray
}

# ============================================================
# Step 2 — detect + select target ST-Link
# ============================================================
Write-Host ""
Write-Host "[2/4] Detecting ST-Link ..." -ForegroundColor Yellow
if (-not $cliPath -or -not (Test-Path -LiteralPath $cliPath))
{
    Write-Host "[ERR] STM32_Programmer_CLI not found." -ForegroundColor Red
    foreach ($p in $script:_cliTried) { Write-Host "      tried: $p" -ForegroundColor DarkGray }
    Write-Host "      請確認有裝 STM32CubeProgrammer 或 STM32CubeIDE" -ForegroundColor DarkGray
    Wait-OnExit 12
}
Write-Host "[OK ] CLI: $cliPath" -ForegroundColor DarkGray

$listOut = ""
try { $listOut = & $cliPath --list st-link 2>&1 | Out-String } catch {}

# Parse probe blocks -> SN + Board Name pairs
$probes = @()
foreach ($line in ($listOut -split "`r?`n"))
{
    if ($line -match 'ST-LINK SN\s*:\s*(\S+)')
    {
        $probes += [PSCustomObject]@{ SN = $matches[1]; Board = "" }
    }
    elseif ($line -match 'Board Name\s*:\s*(\S.*?)\s*$' -and $probes.Count -gt 0)
    {
        $probes[$probes.Count - 1].Board = $matches[1].Trim()
    }
}

if ($probes.Count -eq 0)
{
    Write-Host "[ERR] No ST-Link detected. 檢查 USB 線 / ST-Link 驅動。" -ForegroundColor Red
    Wait-OnExit 1
}

Write-Host ("       偵測到 {0} 顆 ST-Link:" -f $probes.Count) -ForegroundColor DarkGray
foreach ($p in $probes)
{
    Write-Host ("         SN={0}  Board='{1}'" -f $p.SN, $p.Board) -ForegroundColor DarkGray
}

# 選定目標 probe : TARGET_SN (精確) 優先 > TARGET_BOARD (子字串) > 唯一 probe
$target = $null
if ($targetSnCfg)
{
    $target = @($probes | Where-Object { $_.SN -eq $targetSnCfg }) | Select-Object -First 1
    if (-not $target)
    {
        Write-Host "[ERR] 設定的 TARGET_SN=$targetSnCfg 不在已接的 ST-Link 之中。" -ForegroundColor Red
        Write-Host "      確認 G071 板 USB 有插好，或修正 config.ini 的 TARGET_SN。" -ForegroundColor DarkGray
        Wait-OnExit 7
    }
}
elseif ($targetBoard)
{
    $matched = @($probes | Where-Object { $_.Board -and ($_.Board -match [regex]::Escape($targetBoard)) })
    if ($matched.Count -eq 0)
    {
        Write-Host "[ERR] 找不到 Board Name 含 '$targetBoard' 的 ST-Link。" -ForegroundColor Red
        Write-Host "      目前接著的板子不是目標 G071，或 G071 USB 沒插好。" -ForegroundColor DarkGray
        Write-Host "      (若確實要燒別的板，改 config.ini 的 TARGET_BOARD/TARGET_SN)" -ForegroundColor DarkGray
        Wait-OnExit 7
    }
    if ($matched.Count -gt 1)
    {
        Write-Host "[ERR] 有多顆板 Board Name 都含 '$targetBoard'，無法自動判定。" -ForegroundColor Red
        $matched | ForEach-Object { Write-Host ("         SN={0}  Board='{1}'" -f $_.SN, $_.Board) -ForegroundColor DarkGray }
        Write-Host "      請在 config.ini 填 TARGET_SN 鎖定其中一顆。" -ForegroundColor DarkGray
        Wait-OnExit 7
    }
    $target = $matched[0]
}
else
{
    # 沒設任何 target 過濾 : 只允許單一 probe
    if ($probes.Count -gt 1)
    {
        Write-Host "[ERR] 接了多顆 ST-Link 但沒設定 TARGET_BOARD/TARGET_SN。" -ForegroundColor Red
        Write-Host "      為避免誤燒，請在 config.ini 設定目標，或只留一顆板。" -ForegroundColor DarkGray
        Wait-OnExit 7
    }
    $target = $probes[0]
}

$targetSn = $target.SN
Write-Host ("[OK ] 目標: SN={0}  Board='{1}'" -f $target.SN, $target.Board) -ForegroundColor Green

# 所有後續 CLI 連線都帶 sn=<目標>，鎖死這顆板
$connArgs = @("-c", "port=SWD", ("freq=" + $swdFreq), ("reset=" + $resetMode), ("sn=" + $targetSn))

# ============================================================
# Step 3 — Program + Verify (一律 verify，不提供跳過)
# ============================================================
Write-Host ""
Write-Host "[3/4] Program + Verify ..." -ForegroundColor Yellow
$progArgs = $connArgs + @("-w", "$hexFile", "-v")
Write-Host "      exec: STM32_Programmer_CLI $($progArgs -join ' ')" -ForegroundColor DarkGray
& $cliPath @progArgs
$progExit = $LASTEXITCODE
if ($progExit -ne 0)
{
    Write-Host "[ERR] CLI exit $progExit (燒錄或驗證失敗)" -ForegroundColor Red
    Write-Host "      可試：降低 config.ini 的 SWD_FREQ_KHZ 到 1800，或重插 ST-Link USB" -ForegroundColor DarkGray
    Wait-OnExit 5
}
Write-Host "[OK ] Download verified" -ForegroundColor Green

# ============================================================
# Step 4 — hardware reset -> run
# ============================================================
Write-Host ""
Write-Host "[4/4] Post-flash reset ..." -ForegroundColor Yellow
Start-Sleep -Milliseconds 300
$resetArgs = $connArgs + @("--hardRst")
& $cliPath @resetArgs | Out-Null
if ($LASTEXITCODE -eq 0) { Write-Host "[OK ] hardRst sent; APP should be running" -ForegroundColor Green }
else { Write-Host ("[--] hardRst exit {0} (板子可能已自行 reset，通常正常)" -f $LASTEXITCODE) -ForegroundColor DarkGray }

Write-Host ""
Write-Host "============================================================" -ForegroundColor Green
Write-Host " [DONE] G071 firmware updated" -ForegroundColor Green
Write-Host "============================================================" -ForegroundColor Green
Wait-OnExit 0
